function SensTable({f}){
  const br=+f.rate||6.5,bv=+f.vacancy||5,price=+f.price||1,noi=+f.noi||0,eq=(+f.price||0)*(+f.down||25)/100;
  const rates=[br-1,br-0.5,br,br+0.5,br+1],vacs=[bv-5,bv,bv+5,bv+10,bv+15];
  function coc(r,v){const loan=price-eq,mr=r/100/12,n=360;const mp=loan>0&&mr>0?loan*(mr*Math.pow(1+mr,n))/(Math.pow(1+mr,n)-1):0;return eq>0?(noi*(1-Math.max(0,v)/100)-mp*12)/eq*100:0;}
  function cc(v){return v>=10?"#27AE60":v>=6?"#C5993A":v>=0?"#E67E22":"#E53935";}
  return(<div style={{overflowX:"auto"}}><p style={{fontSize:12,color:"#888",marginBottom:8}}>Cash-on-Cash Return - Interest Rate vs. Vacancy</p><table style={{borderCollapse:"collapse",fontSize:13,width:"100%"}}><thead><tr><th style={{padding:"6px 10px",background:"#1B2A4A",color:"#C5993A",textAlign:"left"}}>Rate / Vac</th>{vacs.map(v=><th key={v} style={{padding:"6px 10px",background:"#1B2A4A",color:"#fff",textAlign:"center"}}>{Math.max(0,v).toFixed(0)}pct</th>)}</tr></thead><tbody>{rates.map((r,ri)=>(<tr key={r} style={{background:ri%2===0?"#f8f9fa":"#fff"}}><td style={{padding:"6px 10px",fontWeight:600,color:"#1B2A4A"}}>{r.toFixed(1)}pct</td>{vacs.map(v=>{const val=coc(r,v);return(<td key={v} style={{padding:"6px 10px",textAlign:"center",fontWeight:600,color:cc(val),background:r===br&&v===bv?"#fffde7":"transparent"}}>{val.toFixed(1)}pct</td>);})}</tr>))}</tbody></table><p style={{fontSize:11,color:"#aaa",marginTop:6}}>Yellow = base case | Green 10pct+ | Amber 6-10pct | Orange 0-6pct | Red negative</p></div>);
}

function AIPanel({deal,mode="research"}){
  const [q,setQ]=useState("");const [loading,setLoading]=useState(false);const [history,setHistory]=useState([]);
  const PRESETS=mode==="research"?["Analyze submarket fundamentals - vacancy trends, rent growth, supply pipeline, employment base.","What are current cap rates for this asset class and market? How does our cap rate compare?","What are current DSCR loan, agency, and bridge rates for this deal type?","Identify the top 3 risks for this deal and suggest specific mitigations.","Draft a one-paragraph IC memo narrative for investment committee review."]:["Explain why you scored this category this way.","I disagree with this score - here is my reasoning.","What would need to change to improve this score?","What data am I missing that would affect this score?"];
  const ctx=()=>`Property: ${deal.intake.address||"TBD"}, ${deal.intake.city||""} ${deal.intake.state||""}\nAsset: ${deal.intake.assetType} | Deal: ${deal.intake.dealType} | Units: ${deal.intake.units||"N/A"}\nPrice: $${(+deal.intake.price||0).toLocaleString()} | NOI: $${(+deal.intake.noi||0).toLocaleString()}\nPAIS Score: ${deal.comp.toFixed(1)} - ${deal.b.label}\nScores: ${CATS.map(c=>c.label.split(" ")[0]+":"+deal.scores[c.id]).join(", ")}`;
  const ask=async(query)=>{
    if(!query.trim())return;setLoading(true);
    const newHistory=[...history,{role:"user",content:`Deal context:\n${ctx()}\n\nQuestion: ${query}`}];
    try{
      const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":import.meta.env.VITE_ANTHROPIC_KEY,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,system:mode==="dispute"?"You are a real estate investment analyst reviewing a deal scoring decision. Engage in honest dialogue - acknowledge valid points, push back on weak arguments. Be direct and fair.":"You are a sharp real estate investment analyst. Respond in 3-5 tight paragraphs, no bullet points. Be direct and specific.",messages:newHistory})});
      const d=await r.json();const text=d.content?.find(b=>b.type==="text")?.text||"No response.";
      setHistory([...newHistory,{role:"assistant",content:text}]);
    }catch{setHistory([...newHistory,{role:"assistant",content:"Connection error."}]);}
    setLoading(false);setQ("");
  };
  return(<div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>{PRESETS.map((p,i)=>(<button key={i} onClick={()=>{setQ(p);ask(p);}} style={{padding:"8px 12px",background:"#f0f4ff",border:"1px solid #c8d8ff",borderRadius:6,fontSize:12,color:"#1B2A4A",cursor:"pointer",textAlign:"left",lineHeight:1.4}}>{p.substring(0,65)}...</button>))}</div>{history.length>0&&(<div style={{marginBottom:16,maxHeight:300,overflowY:"auto",display:"flex",flexDirection:"column",gap:8}}>{history.map((m,i)=>(<div key={i} style={{padding:"10px 14px",borderRadius:8,background:m.role==="user"?"#f0f4ff":"#f8f9fa",border:`1px solid ${m.role==="user"?"#c8d8ff":"#e8eaed"}`,fontSize:13,lineHeight:1.6,color:"#1B2A4A"}}><div style={{fontSize:10,fontWeight:700,color:"#aaa",marginBottom:4,textTransform:"uppercase"}}>{m.role==="user"?"You":"PAIS AI"}</div>{m.content.replace(/[\s\S]*Question: /,"")}</div>))}</div>)}<div style={{display:"flex",gap:8}}><textarea value={q} onChange={e=>setQ(e.target.value)} rows={3} placeholder={mode==="dispute"?"Argue, question, or request clarification about this score...":"Ask anything about this deal..."} style={{flex:1,padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:14,fontFamily:"inherit",resize:"vertical"}}/><button onClick={()=>ask(q)} disabled={loading} style={{padding:"0 20px",background:"#1B2A4A",color:"#C5993A",border:"none",borderRadius:8,cursor:"pointer",fontWeight:700,fontSize:14,minWidth:80}}>{loading?"...":"Send"}</button></div>{history.length>0&&<button onClick={()=>setHistory([])} style={{marginTop:8,background:"none",border:"none",color:"#aaa",fontSize:12,cursor:"pointer"}}>Clear conversation</button>}</div>);
}

function AIIntake({onPopulate}){
  const [sources,setSources]=useState([]);const [pasted,setPasted]=useState("");const [extracting,setExtracting]=useState(false);const [preview,setPreview]=useState(null);const [error,setError]=useState("");
  const addPasted=()=>{if(!pasted.trim())return;setSources(s=>[...s,{id:Date.now(),name:"Pasted text",content:pasted,type:"text"}]);setPasted("");};
  const addFile=async(e)=>{const files=Array.from(e.target.files);for(const file of files){const content=await new Promise((res,rej)=>{const reader=new FileReader();if(file.type==="application/pdf"||file.type.startsWith("image/")){reader.onload=()=>res(reader.result);reader.onerror=rej;reader.readAsDataURL(file);}else{reader.onload=()=>res(reader.result);reader.onerror=rej;reader.readAsText(file);}});setSources(s=>[...s,{id:Date.now()+Math.random(),name:file.name,content,type:file.type||"text"}]);}e.target.value="";};
  const SYS=`You are a real estate deal analyst. Extract all available deal information from the provided sources and return ONLY a valid JSON object with these exact keys (use null for any field not found):
{"address":null,"city":null,"state":null,"units":null,"assetType":null,"dealType":null,"price":null,"noi":null,"gri":null,"vacancy":null,"down":null,"rate":null,"yrs":null,"rc":null,"notes":null}
assetType must be one of: SFR, Duplex/Triplex/Quad, Small Multifamily (5-20), Multifamily (21-100), Large Multifamily (100+)
dealType must be one of: Acquisition, Value-Add, Development, Refinance
Return ONLY the JSON. No explanation, no markdown.`;
  const extract=async()=>{
    if(sources.length===0){setError("Add at least one source first.");return;}
    setExtracting(true);setError("");setPreview(null);
    try{
      const userContent=[];
      for(const src of sources){if((src.type.startsWith("image/")||src.type==="application/pdf")&&src.content.startsWith("data:")){const blockType=src.type==="application/pdf"?"document":"image";userContent.push({type:blockType,source:{type:"base64",media_type:src.type,data:src.content.split(",")[1]}});userContent.push({type:"text",text:`[Above: ${src.name}]`});}else{userContent.push({type:"text",text:`--- SOURCE: ${src.name} ---\n${src.content}\n--- END ---`});}}
      userContent.push({type:"text",text:"Extract all real estate deal fields."});
      const resp=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":import.meta.env.VITE_ANTHROPIC_KEY,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,system:SYS,messages:[{role:"user",content:userContent}]})});
      const data=await resp.json();const raw=data.content?.find(b=>b.type==="text")?.text||"";
      setPreview(JSON.parse(raw.replace(/`{3}json|`{3}/g,"").trim()));
    }catch(e){setError("Extraction failed: "+e.message);}
    setExtracting(false);
  };
  const AT=["SFR","Duplex/Triplex/Quad","Small Multifamily (5-20)","Multifamily (21-100)","Large Multifamily (100+)"];
  const DT=["Acquisition","Value-Add","Development","Refinance"];
  const apply=()=>{if(!preview)return;onPopulate({address:preview.address||"",city:preview.city||"",state:preview.state||"",units:preview.units!=null?String(preview.units):"",assetType:AT.includes(preview.assetType)?preview.assetType:"Multifamily (21-100)",dealType:DT.includes(preview.dealType)?preview.dealType:"Acquisition",price:preview.price!=null?String(preview.price):"",noi:preview.noi!=null?String(preview.noi):"",gri:preview.gri!=null?String(preview.gri):"",vacancy:preview.vacancy!=null?String(preview.vacancy):"5",down:preview.down!=null?String(preview.down):"25",rate:preview.rate!=null?String(preview.rate):"6.5",yrs:preview.yrs!=null?String(preview.yrs):"30",rc:preview.rc!=null?String(preview.rc):"",notes:preview.notes||""});setPreview(null);setSources([]);};
  const LABELS={address:"Address",city:"City",state:"State",units:"Units",assetType:"Asset Type",dealType:"Deal Type",price:"Asking Price",noi:"NOI (annual)",gri:"Gross Rental Income",vacancy:"Vacancy pct",down:"Down Payment pct",rate:"Loan Rate pct",yrs:"Amortization",rc:"Replacement Cost",notes:"Notes"};
  const fv=(k,v)=>{if(v==null)return null;if(["price","noi","gri","rc"].includes(k))return "$"+Number(v).toLocaleString();if(["vacancy","down","rate"].includes(k))return v+"pct";if(k==="yrs")return v+" yrs";return String(v);};
  return(<div><div style={{marginBottom:24,padding:20,background:"#fff8e1",borderRadius:10,border:"1.5px solid #C5993A"}}><p style={{fontSize:14,color:"#7a5c00",fontWeight:700,marginBottom:4}}>AI-Assisted Deal Intake</p><p style={{fontSize:13,color:"#a07820",lineHeight:1.6,margin:0}}>Add sources - paste an OM excerpt, broker email, Zillow listing, rent roll, or raw numbers. Upload PDFs or images. Claude reads everything together and populates every PAIS field it can find.</p></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginBottom:20}}><Card><SH title="Paste Text"/><textarea value={pasted} onChange={e=>setPasted(e.target.value)} rows={9} placeholder="Paste anything - broker email, OM excerpt, Zillow listing text, rent roll figures, or raw numbers. Each paste becomes its own source." style={{width:"100%",padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:13,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box",lineHeight:1.6}}/><button onClick={addPasted} disabled={!pasted.trim()} style={{marginTop:10,padding:"8px 18px",background:pasted.trim()?"#1B2A4A":"#e0e0e0",color:pasted.trim()?"#C5993A":"#aaa",border:"none",borderRadius:6,fontSize:13,fontWeight:700,cursor:pasted.trim()?"pointer":"default"}}>+ Add Source</button></Card><Card><SH title="Upload Files"/><label style={{display:"block",padding:"28px 20px",border:"2px dashed #C5993A",borderRadius:10,textAlign:"center",cursor:"pointer",background:"#fffbf0",marginBottom:12}}><input type="file" multiple accept=".pdf,.txt,.csv,.png,.jpg,.jpeg,.webp" onChange={addFile} style={{display:"none"}}/><div style={{fontSize:32,marginBottom:8}}>+</div><div style={{fontSize:13,color:"#7a5c00",fontWeight:700}}>Click to upload</div><div style={{fontSize:11,color:"#aaa",marginTop:4}}>PDF, TXT, CSV, PNG, JPG</div></label><p style={{fontSize:11,color:"#aaa",lineHeight:1.6}}>PDFs: offering memos, rent rolls, T12s<br/>Images: screenshots, scanned docs, listing photos<br/>Text: exported spreadsheets, broker packages</p></Card></div>{sources.length>0&&<Card style={{marginBottom:20}}><SH title={"Sources ("+sources.length+")"}/><div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:16}}>{sources.map(s=>(<div key={s.id} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 14px",background:"#f8f9fa",borderRadius:8,border:"1px solid #eee"}}><div style={{display:"flex",alignItems:"center",gap:10}}><span style={{fontSize:18}}>{s.type==="text"?"[T]":s.type.startsWith("image")?"[I]":"[D]"}</span><div><div style={{fontSize:13,fontWeight:600,color:"#1B2A4A"}}>{s.name}</div><div style={{fontSize:11,color:"#aaa"}}>{s.type==="text"?s.content.substring(0,80).replace(/[\n\r]/g," ")+"...":s.type}</div></div></div><button onClick={()=>setSources(ss=>ss.filter(x=>x.id!==s.id))} style={{background:"none",border:"none",color:"#ccc",fontSize:18,cursor:"pointer"}}>x</button></div>))}</div><button onClick={extract} disabled={extracting} style={{width:"100%",padding:"13px 0",background:extracting?"#e0e0e0":"#1B2A4A",color:extracting?"#aaa":"#C5993A",border:"none",borderRadius:8,fontSize:15,fontWeight:800,cursor:extracting?"default":"pointer"}}>{extracting?"Extracting deal data...":"Extract Deal Data from "+sources.length+" Source"+(sources.length>1?"s":"")}</button></Card>}{error&&<div style={{padding:14,background:"#ffebee",borderRadius:8,border:"1px solid #E53935",color:"#c62828",fontSize:13,marginBottom:16}}>{error}</div>}{preview&&<Card style={{border:"2px solid #27AE60"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><div><p style={{fontSize:15,fontWeight:800,color:"#1B2A4A",margin:0}}>Extraction Complete</p><p style={{fontSize:12,color:"#888",marginTop:2}}>Green = found | Grey = not in sources.</p></div><div style={{display:"flex",gap:10}}><button onClick={()=>setPreview(null)} style={{padding:"8px 16px",background:"#f0f0f0",color:"#666",border:"none",borderRadius:6,fontSize:13,cursor:"pointer"}}>Discard</button><button onClick={apply} style={{padding:"8px 20px",background:"#27AE60",color:"#fff",border:"none",borderRadius:6,fontSize:13,fontWeight:700,cursor:"pointer"}}>Apply to Deal Form</button></div></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>{Object.entries(LABELS).filter(([k])=>k!=="notes").map(([k,l])=>{const val=fv(k,preview[k]);const found=val!==null;return(<div key={k} style={{padding:"10px 14px",borderRadius:8,background:found?"#e8f5e9":"#f8f8f8",border:`1px solid ${found?"#a5d6a7":"#eee"}`}}><div style={{fontSize:10,color:found?"#2e7d32":"#aaa",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:3}}>{l}</div><div style={{fontSize:14,fontWeight:found?700:400,color:found?"#1B2A4A":"#ccc"}}>{found?val:"--"}</div></div>);})}</div>{preview.notes&&<div style={{marginTop:12,padding:"10px 14px",background:"#e8f5e9",borderRadius:8,border:"1px solid #a5d6a7"}}><div style={{fontSize:10,color:"#2e7d32",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:4}}>Deal Notes Extracted</div><div style={{fontSize:13,color:"#1B2A4A",lineHeight:1.6}}>{preview.notes}</div></div>}</Card>}</div>);
}

function OfferingDocs({deal,trial,onUpgrade}){
  const [selectedPkg,setSelectedPkg]=useState(null);const [showAck,setShowAck]=useState(false);const [ackChecked,setAckChecked]=useState(false);const [ackName,setAckName]=useState("");const [generating,setGenerating]=useState(false);const [generated,setGenerated]=useState(null);const [showWatermark,setShowWatermark]=useState(true);const [showRemove,setShowRemove]=useState(false);
  const [offeringType,setOfferingType]=useState("506b");const [entityName,setEntityName]=useState("");const [entityType,setEntityType]=useState("LLC");const [stateForm,setStateForm]=useState("Delaware");const [targetRaise,setTargetRaise]=useState("");const [minInv,setMinInv]=useState("");const [prefReturn,setPrefReturn]=useState("");const [carry,setCarry]=useState("");const [holdPeriod,setHoldPeriod]=useState("");const [gpCo,setGpCo]=useState("");const [useProceeds,setUseProceeds]=useState("");const [conflicts,setConflicts]=useState("");const [acqFee,setAcqFee]=useState("");const [mgmtFee,setMgmtFee]=useState("");const [dispFee,setDispFee]=useState("");
  const [managers,setManagers]=useState([{name:"",title:"",equity:"",salary:"",bio:"",lit:"no"}]);
  if(trial.rank<1)return(<div style={{padding:60,textAlign:"center"}}><div style={{fontSize:40,marginBottom:16}}>[ locked ]</div><p style={{fontSize:16,fontWeight:700,color:"#1B2A4A",marginBottom:8}}>Offering Documents require a paid plan</p><p style={{fontSize:14,color:"#666",marginBottom:24}}>Available on Starter ($9.99/mo) and above. Each document package is a separate add-on purchase.</p><button onClick={onUpgrade} style={{padding:"10px 28px",background:"#C5993A",color:"#1B2A4A",border:"none",borderRadius:8,fontSize:14,fontWeight:700,cursor:"pointer"}}>View Plans</button></div>);
  const addM=()=>setManagers(m=>[...m,{name:"",title:"",equity:"",salary:"",bio:"",lit:"no"}]);
  const updM=(i,f,v)=>setManagers(m=>m.map((x,idx)=>idx===i?{...x,[f]:v}:x));
  const remM=(i)=>setManagers(m=>m.filter((_,idx)=>idx!==i));
  const begin=(pkg)=>{if(pkg.tier==="contact")return;setSelectedPkg(pkg);setShowAck(true);setAckChecked(false);setAckName("");};
  const confirm=async()=>{
    if(!ackChecked||!ackName.trim())return;setShowAck(false);setGenerating(true);setGenerated(null);setShowWatermark(true);
    const ctx=`Property: ${deal.intake.address||"TBD"}, ${deal.intake.city||""} ${deal.intake.state||""}\nAsset: ${deal.intake.assetType} | Units: ${deal.intake.units||"N/A"}\nPrice: $${(+deal.intake.price||0).toLocaleString()} | NOI: $${(+deal.intake.noi||0).toLocaleString()}\nCap Rate: ${fmtP(deal.fin.capRate)} | DSCR: ${fmt(deal.fin.dscr)}x\nPAIS Score: ${deal.comp.toFixed(0)} - ${deal.b.label}\nEntity: ${entityName||"[ENTITY]"} (${entityType}) - ${stateForm}\nOffering: ${offeringType} | Target Raise: $${(+targetRaise||0).toLocaleString()} | Min Inv: $${(+minInv||0).toLocaleString()}\nPref Return: ${prefReturn||"[X]"}% | Carry: ${carry||"[X]"}% | Hold: ${holdPeriod||"[X]"} yrs\nGP Co-Invest: ${gpCo||"[X]"}% | Acq Fee: ${acqFee||"[X]"}% | Mgmt Fee: ${mgmtFee||"[X]"}%\nUse of Proceeds: ${useProceeds||"[To be specified]"}\nManagement: ${managers.map(m=>`${m.name} (${m.title}, ${m.equity}% equity)`).join("; ")}\nConflicts: ${conflicts||"None disclosed"}`;
    try{
      const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json","x-api-key":import.meta.env.VITE_ANTHROPIC_KEY,"anthropic-version":"2023-06-01","anthropic-dangerous-direct-browser-access":"true"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,system:"You are a securities attorney drafting real estate offering documents. Generate a professional draft based on the deal information provided. Use proper legal formatting with clearly labeled sections. Include all required disclosures for the offering type. Flag any missing information with [REQUIRED: description]. End with a prominent notice that this document requires attorney review before use.",messages:[{role:"user",content:`Generate a draft ${selectedPkg.label} for this deal:\n\n${ctx}`}]})});
      const d=await r.json();const text=d.content?.find(b=>b.type==="text")?.text||"Generation failed.";
      setGenerated(text);
    }catch(e){setGenerated("Error: "+e.message);}
    setGenerating(false);
  };
  const download=()=>{if(!generated)return;const wm=showWatermark?"\n\n"+"=".repeat(60)+"\nDRAFT - FOR ATTORNEY REVIEW ONLY - NOT FOR DISTRIBUTION\n"+"=".repeat(60)+"\n\n":"";const content=selectedPkg.label.toUpperCase()+wm+generated+"\n\n---\nGenerated by PAIS Pro | Acknowledged by: "+ackName+" | "+new Date().toLocaleString();const blob=new Blob([content],{type:"text/plain"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=(selectedPkg.label.replace(/\s+/g,"_"))+"_DRAFT.txt";a.click();URL.revokeObjectURL(url);};
  return(<div><h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:6,fontWeight:700}}>Offering Documents</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Each document package is a separate purchase. Complete the intake fields below, then select a package to generate.</p>
  {showAck&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{maxWidth:560,width:"90%",background:"#fff",borderRadius:16,padding:"36px 40px",boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}}><h3 style={{fontSize:18,fontWeight:800,color:"#1B2A4A",marginBottom:16}}>Important Disclaimer</h3><div style={{padding:16,background:"#fff8e1",borderRadius:8,border:"1.5px solid #C5993A",fontSize:13,lineHeight:1.7,color:"#7a5c00",marginBottom:20}}>The documents generated by this platform are AI-assisted drafts for informational purposes only. They do not constitute legal advice and are not a substitute for review by a qualified securities attorney licensed in the relevant jurisdiction. PAIS Pro expressly disclaims all liability arising from reliance on generated documents without independent legal review. These documents may not comply with applicable federal or state securities laws without attorney verification and modification. By proceeding you acknowledge that you will seek qualified legal counsel before using these documents in any offering or distribution to investors.</div><div style={{marginBottom:16,display:"flex",alignItems:"flex-start",gap:12}}><input type="checkbox" id="ack" checked={ackChecked} onChange={e=>setAckChecked(e.target.checked)} style={{marginTop:3,width:16,height:16}}/><label htmlFor="ack" style={{fontSize:13,color:"#333",lineHeight:1.5,cursor:"pointer"}}>I have read and understand the above disclaimer. I acknowledge that these documents are AI-generated drafts requiring attorney review and accept sole responsibility for their use.</label></div><div style={{marginBottom:20}}><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:4}}>Type your full name to confirm</label><input value={ackName} onChange={e=>setAckName(e.target.value)} placeholder="Your full legal name" style={{width:"100%",padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:14,fontFamily:"inherit",boxSizing:"border-box"}}/></div><div style={{display:"flex",gap:12}}><button onClick={()=>setShowAck(false)} style={{flex:1,padding:"10px 0",background:"#f0f0f0",color:"#666",border:"none",borderRadius:8,fontSize:14,cursor:"pointer"}}>Cancel</button><button onClick={confirm} disabled={!ackChecked||!ackName.trim()} style={{flex:2,padding:"10px 0",background:ackChecked&&ackName.trim()?"#1B2A4A":"#e0e0e0",color:ackChecked&&ackName.trim()?"#C5993A":"#aaa",border:"none",borderRadius:8,fontSize:14,fontWeight:700,cursor:ackChecked&&ackName.trim()?"pointer":"default"}}>I Acknowledge - Generate Document</button></div></div></div>}
  {showRemove&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{maxWidth:440,width:"90%",background:"#fff",borderRadius:12,padding:"28px 32px"}}><h3 style={{fontSize:16,fontWeight:800,color:"#1B2A4A",marginBottom:12}}>Remove Watermark</h3><p style={{fontSize:13,color:"#555",lineHeight:1.6,marginBottom:20}}>By removing the watermark you confirm you have read the disclaimer and accept sole responsibility for the use of these documents. PAIS Pro expressly disclaims all liability.</p><div style={{display:"flex",gap:10}}><button onClick={()=>setShowRemove(false)} style={{flex:1,padding:"9px 0",background:"#f0f0f0",color:"#666",border:"none",borderRadius:6,cursor:"pointer"}}>Cancel</button><button onClick={()=>{setShowWatermark(false);setShowRemove(false);}} style={{flex:1,padding:"9px 0",background:"#E53935",color:"#fff",border:"none",borderRadius:6,fontWeight:700,cursor:"pointer"}}>Remove Watermark</button></div></div></div>}
  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginBottom:20}}>
    <Card><SH title="Issuer and Entity"/><div style={{display:"flex",flexDirection:"column",gap:12}}><F label="Legal Entity Name" value={entityName} onChange={setEntityName} placeholder="Maple Street Multifamily LLC"/><Sel label="Entity Type" value={entityType} onChange={setEntityType} options={["LLC","LP","Corp","DST","TIC","Other"]}/><F label="State of Formation" value={stateForm} onChange={setStateForm} placeholder="Delaware"/><Sel label="Offering Type" value={offeringType} onChange={setOfferingType} options={OFFERING_TYPES}/></div></Card>
    <Card><SH title="Offering Terms"/><div style={{display:"flex",flexDirection:"column",gap:12}}><F label="Target Raise ($)" value={targetRaise} onChange={setTargetRaise} placeholder="2500000" type="number"/><F label="Minimum Investment ($)" value={minInv} onChange={setMinInv} placeholder="50000" type="number"/><F label="Preferred Return (%)" value={prefReturn} onChange={setPrefReturn} placeholder="8" type="number"/><F label="GP Carry / Promote (%)" value={carry} onChange={setCarry} placeholder="20" type="number"/></div></Card>
    <Card><SH title="Economics"/><div style={{display:"flex",flexDirection:"column",gap:12}}><F label="Hold Period (years)" value={holdPeriod} onChange={setHoldPeriod} placeholder="5" type="number"/><F label="GP Co-Investment (%)" value={gpCo} onChange={setGpCo} placeholder="5" type="number"/><F label="Acquisition Fee (%)" value={acqFee} onChange={setAcqFee} placeholder="1.5" type="number"/><F label="Asset Management Fee (%)" value={mgmtFee} onChange={setMgmtFee} placeholder="2" type="number"/><F label="Disposition Fee (%)" value={dispFee} onChange={setDispFee} placeholder="1" type="number"/></div></Card>
    <Card><SH title="Use of Proceeds and Conflicts"/><div style={{display:"flex",flexDirection:"column",gap:12}}><div><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:4}}>Use of Proceeds</label><textarea value={useProceeds} onChange={e=>setUseProceeds(e.target.value)} rows={4} placeholder="e.g. 85pct acquisition, 10pct renovation reserves, 5pct working capital and closing costs" style={{width:"100%",padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:13,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}}/></div><div><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:4}}>Conflicts of Interest Disclosure</label><textarea value={conflicts} onChange={e=>setConflicts(e.target.value)} rows={4} placeholder="Disclose any conflicts between GP and LP interests, related-party transactions, affiliated service providers, competing investments..." style={{width:"100%",padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:13,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}}/></div></div></Card>
  </div>
  <Card style={{marginBottom:20}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}><SH title="Management Team / Directors / Officers"/><button onClick={addM} style={{padding:"6px 14px",background:"#1B2A4A",color:"#C5993A",border:"none",borderRadius:6,fontSize:12,fontWeight:700,cursor:"pointer"}}>+ Add Person</button></div>{managers.map((m,i)=>(<div key={i} style={{padding:16,border:"1px solid #e8eaed",borderRadius:8,marginBottom:12,background:"#fafafa"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><span style={{fontSize:13,fontWeight:700,color:"#1B2A4A"}}>Person {i+1}</span>{managers.length>1&&<button onClick={()=>remM(i)} style={{background:"none",border:"none",color:"#E53935",fontSize:12,cursor:"pointer"}}>Remove</button>}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:12,marginBottom:12}}><F label="Full Legal Name" value={m.name} onChange={v=>updM(i,"name",v)} placeholder="Jane Smith"/><F label="Title / Role" value={m.title} onChange={v=>updM(i,"title",v)} placeholder="Managing Member"/><F label="Equity (%)" value={m.equity} onChange={v=>updM(i,"equity",v)} placeholder="50" type="number"/><F label="Annual Compensation ($)" value={m.salary} onChange={v=>updM(i,"salary",v)} placeholder="120000" type="number"/></div><div style={{marginBottom:12}}><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:4}}>Biography and Track Record</label><textarea value={m.bio} onChange={e=>updM(i,"bio",e.target.value)} rows={3} placeholder="Professional background, years of experience, number of prior deals, total capital raised, relevant credentials..." style={{width:"100%",padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:13,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}}/></div><div><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:4}}>Prior Litigation or Regulatory Action</label><select value={m.lit} onChange={e=>updM(i,"lit",e.target.value)} style={{padding:"8px 12px",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontFamily:"inherit",background:"#fff"}}><option value="no">None to disclose</option><option value="yes">Yes - disclosure required</option></select>{m.lit==="yes"&&<textarea onChange={e=>updM(i,"litDetail",e.target.value)} rows={2} placeholder="Describe the litigation or regulatory matter..." style={{width:"100%",marginTop:8,padding:"10px 14px",border:"1.5px solid #E53935",borderRadius:8,fontSize:13,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}}/>}</div></div>))}</Card>
  <Card style={{marginBottom:20}}><SH title="Select Document Package"/><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>{DOC_PACKAGES.map(pkg=>(<div key={pkg.id} style={{padding:16,border:`1.5px solid ${pkg.tier==="contact"?"#ddd":"#e8eaed"}`,borderRadius:10,background:pkg.tier==="contact"?"#fafafa":"#fff"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}><div><div style={{fontWeight:700,color:"#1B2A4A",fontSize:14}}>{pkg.label}</div><div style={{fontSize:12,color:"#888",marginTop:2,lineHeight:1.4}}>{pkg.desc}</div></div><div style={{textAlign:"right",marginLeft:12,flexShrink:0}}>{pkg.price?<div style={{fontSize:20,fontWeight:900,color:"#C5993A"}}>${pkg.price.toLocaleString()}</div>:<div style={{fontSize:12,fontWeight:700,color:"#888"}}>Contact us</div>}</div></div>{pkg.tier==="contact"?<button style={{width:"100%",padding:"8px 0",background:"#f0f0f0",color:"#888",border:"none",borderRadius:6,fontSize:13,cursor:"default"}}>Contact for Pricing</button>:<button onClick={()=>begin(pkg)} style={{width:"100%",padding:"8px 0",background:"#1B2A4A",color:"#C5993A",border:"none",borderRadius:6,fontSize:13,fontWeight:700,cursor:"pointer"}}>Buy and Generate - ${pkg.price.toLocaleString()}</button>}</div>))}</div><p style={{fontSize:11,color:"#aaa",marginTop:16,textAlign:"center"}}>Note: Reg CF requires a registered funding portal intermediary. Reg A+ requires attorney involvement from the outset. Contact us for both.</p></Card>
  {generating&&<Card style={{textAlign:"center",padding:40}}><p style={{fontSize:14,color:"#666"}}>Generating {selectedPkg?.label}...</p></Card>}
  {generated&&<Card style={{border:"2px solid #27AE60"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}><div><p style={{fontSize:15,fontWeight:800,color:"#1B2A4A",margin:0}}>{selectedPkg?.label} - Draft Generated</p>{showWatermark&&<p style={{fontSize:12,color:"#E53935",fontWeight:700,marginTop:2}}>DRAFT - FOR ATTORNEY REVIEW ONLY</p>}</div><div style={{display:"flex",gap:10}}>{showWatermark?<button onClick={()=>setShowRemove(true)} style={{padding:"8px 16px",background:"#fff3e0",color:"#E67E22",border:"1.5px solid #E67E22",borderRadius:6,fontSize:12,fontWeight:700,cursor:"pointer"}}>Remove Watermark</button>:<span style={{fontSize:12,color:"#27AE60",fontWeight:700,padding:"8px 0"}}>Watermark removed</span>}<button onClick={download} style={{padding:"8px 18px",background:"#1B2A4A",color:"#C5993A",border:"none",borderRadius:6,fontSize:13,fontWeight:700,cursor:"pointer"}}>Download</button></div></div>{showWatermark&&<div style={{padding:"8px 14px",background:"#ffebee",borderRadius:6,border:"1px solid #E53935",marginBottom:12,fontSize:12,color:"#c62828",fontWeight:700,textAlign:"center"}}>DRAFT - FOR ATTORNEY REVIEW ONLY - NOT FOR DISTRIBUTION TO INVESTORS</div>}<div style={{maxHeight:400,overflowY:"auto",padding:16,background:"#f8f9fa",borderRadius:8,fontSize:13,lineHeight:1.8,color:"#1B2A4A",whiteSpace:"pre-wrap",fontFamily:"monospace"}}>{generated}</div></Card>}
  </div>);
}

export default function PAISPro(){
  const trial=getTrialState();
  const [tab,setTab]=useState("aiintake");const [pipe,setPipe]=useState([]);const [modal,setModal]=useState(false);
  const [weights,setWeights]=useState(Object.fromEntries(CATS.map(c=>[c.id,c.weight])));
  const [invStrategy,setInvStrategy]=useState("Value-Add");
  const [intake,setI]=useState({address:"",city:"",state:"",units:"",assetType:"Multifamily (21-100)",dealType:"Acquisition",price:"",noi:"",gri:"",vacancy:"5",down:"25",rate:"6.5",yrs:"30",rc:"",notes:""});
  const [scores,setSc]=useState({financial:70,market:70,physical:70,operational:70,location:70,strategic:70});
  const [hfT,setHfT]=useState(Object.fromEntries(HF_DEFAULTS.map(f=>[f.id,f.def])));
  const [hfO,setHfO]=useState(Object.fromEntries(HF_DEFAULTS.map(f=>[f.id,"auto"])));
  const [amends,setAm]=useState({a1:false,a2:false,a3:false});
  const [opProfile,setOpProfile]=useState("Syndicator / GP");const [minCoC,setMinCoC]=useState("8");const [minIRR,setMinIRR]=useState("15");const [holdPref,setHoldPref]=useState("5-7 years");const [riskTol,setRiskTol]=useState("Balanced");const [targetMarkets,setTargetMarkets]=useState("");const [assetPrefs,setAssetPrefs]=useState([]);const [maxPrice,setMaxPrice]=useState("");
  const fin=calcFin(intake);const comp=getComposite(scores,weights);const b=getBand(comp);const deal={intake,scores,weights,amends,fin,comp,b};
  const flagged=HF_DEFAULTS.filter(f=>{if(hfO[f.id]==="flagged")return true;if(hfO[f.id]==="clear")return false;if(f.metric&&fin[f.metric]!==undefined){const val=fin[f.metric];if(f.dir==="above")return val>hfT[f.id];if(f.dir==="below")return val<hfT[f.id];}return false;});
  const applyStrategy=(strat)=>{setInvStrategy(strat);if(STRATEGY_WEIGHTS[strat])setWeights({...STRATEGY_WEIGHTS[strat]});};
  const populate=(fields)=>{setI(p=>({...p,...fields}));setTab("intake");};
  const save=()=>{if(trial.rank===0&&pipe.length>=3){setModal(true);return;}setPipe(p=>[{id:Date.now(),address:intake.address||"Untitled",city:intake.city,state:intake.state,assetType:intake.assetType,comp,band:b.label,price:intake.price,capRate:fin.capRate,saved:new Date().toLocaleString()},...p]);setTab("pipeline");};
  const isF=trial.rank===0;
  const TABS=[{id:"aiintake",label:"AI Intake",minRank:1},{id:"profile",label:"Investor Profile",minRank:1},{id:"intake",label:"Deal Intake",minRank:0},{id:"scoring",label:"PAIS Scoring",minRank:1},{id:"fin",label:"Financial Model",minRank:0},{id:"sens",label:"Sensitivity",minRank:1},{id:"filters",label:"Hard Filters",minRank:1},{id:"ai",label:"AI Research",minRank:2},{id:"offdocs",label:"Offering Documents",minRank:1},{id:"results",label:"Results and Memo",minRank:1},{id:"pipeline",label:`Pipeline (${pipe.length})`,minRank:0}];

  if(trial.isExpired&&!trial.isPaid)return(<div style={{fontFamily:"Georgia,serif",background:"#f4f5f7",minHeight:"100vh"}}><div style={{background:"#1B2A4A",borderBottom:"3px solid #C5993A",padding:"16px 24px"}}><span style={{fontSize:22,fontWeight:700,color:"#C5993A"}}>PAIS</span><span style={{fontSize:13,color:"#8ca0bf",marginLeft:10}}>PROPERTY ACQUISITION INTELLIGENCE SCORE</span></div><div style={{maxWidth:580,margin:"80px auto",padding:"0 24px",textAlign:"center"}}><div style={{background:"#fff",borderRadius:16,border:"2px solid #C5993A",padding:"48px 40px",boxShadow:"0 8px 40px rgba(0,0,0,0.10)"}}><div style={{fontSize:48,marginBottom:16}}>[ locked ]</div><h2 style={{fontSize:24,fontWeight:800,color:"#1B2A4A",marginBottom:8}}>Your Trial Has Ended</h2><p style={{fontSize:15,color:"#666",lineHeight:1.7,marginBottom:8}}>Your 14-day free trial has expired. All your saved deals are locked and waiting.</p><p style={{fontSize:13,color:"#aaa",marginBottom:32}}>No deals are deleted. Everything is preserved.</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:24}}>{PLANS.map(p=><PlanCard key={p.tier} p={p} onClick={()=>simUpgrade(p.tier)}/>)}</div><p style={{fontSize:11,color:"#bbb"}}>Billed via Stripe - Cancel anytime - Annual plans save 20pct</p><p style={{fontSize:10,color:"#ddd",marginTop:4}}>[Demo: click a plan to simulate upgrade]</p></div></div></div>);

  return(<div style={{fontFamily:"Georgia,serif",background:"#f4f5f7",minHeight:"100vh"}}>
    {!trial.isPaid&&!trial.isExpired&&<div style={{background:trial.remaining<=3?"#fff3e0":"#f0f4ff",borderBottom:`2px solid ${trial.remaining<=3?"#E67E22":"#4A90D9"}`,padding:"8px 24px",display:"flex",alignItems:"center",justifyContent:"center",gap:16}}><span style={{fontSize:13,color:trial.remaining<=3?"#bf5000":"#1B2A4A",fontWeight:trial.remaining<=3?700:400}}>{trial.remaining<=3?"Warning: ":"Info: "}{trial.remaining} day{trial.remaining!==1?"s":""} remaining in your free trial.{trial.remaining<=3?" Upgrade now to avoid losing access.":" Full access during trial."}</span><button onClick={()=>setModal(true)} style={{padding:"5px 16px",background:trial.remaining<=3?"#E67E22":"#1B2A4A",color:"#fff",border:"none",borderRadius:6,fontSize:12,fontWeight:700,cursor:"pointer"}}>Upgrade</button></div>}
    {isF&&!trial.isExpired&&<div style={{background:"#f8f9fa",borderBottom:"1px solid #e8eaed",padding:"6px 24px",display:"flex",alignItems:"center",justifyContent:"center",gap:16}}><span style={{fontSize:12,color:"#888"}}>Free plan: cap rate and cash-on-cash only. {pipe.length}/3 deals saved.</span><button onClick={()=>setModal(true)} style={{padding:"4px 12px",background:"#C5993A",color:"#1B2A4A",border:"none",borderRadius:4,fontSize:11,fontWeight:700,cursor:"pointer"}}>Upgrade from $9.99/mo</button></div>}
    <div style={{background:"#1B2A4A",borderBottom:"3px solid #C5993A"}}>
      <div style={{maxWidth:1300,margin:"0 auto",padding:"16px 24px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div><div style={{display:"flex",alignItems:"baseline",gap:10}}><span style={{fontSize:22,fontWeight:700,color:"#C5993A",letterSpacing:"0.04em"}}>PAIS</span><span style={{fontSize:13,color:"#8ca0bf",letterSpacing:"0.08em",textTransform:"uppercase"}}>Property Acquisition Intelligence Score</span></div><div style={{fontSize:11,color:"#5a7090",marginTop:2}}>PROFESSIONAL DEAL EVALUATION PLATFORM</div></div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          {flagged.length>0&&<div style={{padding:"6px 14px",background:"#ffebee",border:"1.5px solid #E53935",borderRadius:6,fontSize:12,color:"#E53935",fontWeight:700}}>Flag: {flagged.length}</div>}
          <div style={{textAlign:"center",padding:"8px 20px",background:b.bg,border:`2px solid ${b.border}`,borderRadius:8}}><div style={{fontSize:26,fontWeight:800,color:b.color,lineHeight:1}}>{comp.toFixed(0)}</div><div style={{fontSize:10,color:b.color,fontWeight:700,textTransform:"uppercase"}}>{b.label}</div></div>
          <button onClick={save} style={{padding:"8px 18px",background:"#C5993A",color:"#1B2A4A",border:"none",borderRadius:6,fontSize:13,fontWeight:700,cursor:"pointer"}}>+ Save</button>
          {trial.isPaid&&<div style={{padding:"5px 12px",background:"#27AE60",color:"#fff",borderRadius:6,fontSize:11,fontWeight:700}}>{trial.tier.toUpperCase()}</div>}
        </div>
      </div>
      <div style={{maxWidth:1300,margin:"0 auto",padding:"0 24px",display:"flex",gap:2,overflowX:"auto"}}>
        {TABS.map(t=>{const locked=trial.rank<t.minRank;return(<button key={t.id} onClick={()=>setTab(t.id)} style={{padding:"10px 16px",background:tab===t.id?"#C5993A":"transparent",color:tab===t.id?"#1B2A4A":locked?"#4a6080":"#8ca0bf",border:"none",cursor:"pointer",fontSize:12,fontWeight:tab===t.id?700:400,borderRadius:"4px 4px 0 0",whiteSpace:"nowrap"}}>{locked?"[L] ":""}{t.label}</button>);})}
      </div>
    </div>
    <div style={{maxWidth:1300,margin:"0 auto",padding:"28px 24px"}}>

      {tab==="aiintake"&&<div style={{position:"relative"}}>{isF&&<Locked minTier="starter" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:6,fontWeight:700}}>AI Deal Intake</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Paste or upload anything - OM, broker email, Zillow listing, rent roll, raw numbers. Claude extracts every PAIS field automatically.</p><AIIntake onPopulate={populate}/></div>}

      {tab==="profile"&&<div style={{position:"relative"}}>{isF&&<Locked minTier="starter" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:6,fontWeight:700}}>Investor Profile</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Set your mandate. Strategy selection auto-adjusts PAIS category weights.</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginBottom:20}}><Card><SH title="Investment Strategy"/><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>{Object.keys(STRATEGY_WEIGHTS).map(s=>(<div key={s} onClick={()=>applyStrategy(s)} style={{padding:"10px 14px",border:`2px solid ${invStrategy===s?"#C5993A":"#e8eaed"}`,borderRadius:8,cursor:"pointer",background:invStrategy===s?"#fff8e1":"#fafafa",fontSize:13,fontWeight:invStrategy===s?700:400,color:"#1B2A4A"}}>{s}</div>))}</div></Card><Card><SH title="Return Objectives"/><div style={{display:"flex",flexDirection:"column",gap:12}}><F label="Minimum Cash-on-Cash (%)" value={minCoC} onChange={setMinCoC} placeholder="8" type="number"/><F label="Minimum Target IRR (%)" value={minIRR} onChange={setMinIRR} placeholder="15" type="number"/><Sel label="Preferred Hold Period" value={holdPref} onChange={setHoldPref} options={["1-3 years","3-5 years","5-7 years","7-10 years","10+ years"]}/></div></Card><Card><SH title="Operator Profile and Risk"/><div style={{display:"flex",flexDirection:"column",gap:12}}><Sel label="Operator Profile" value={opProfile} onChange={setOpProfile} options={["Individual Investor","Syndicator / GP","Family Office","Institutional Buyer","Broker / Advisor","Developer"]}/><Sel label="Risk Tolerance" value={riskTol} onChange={setRiskTol} options={["Conservative (Core)","Moderate (Core-Plus)","Balanced (Value-Add)","Aggressive (Opportunistic)"]}/><F label="Maximum Acquisition Price ($)" value={maxPrice} onChange={setMaxPrice} placeholder="10000000" type="number"/></div></Card><Card><SH title="Asset and Market Preferences"/><F label="Target Markets / Metros" value={targetMarkets} onChange={setTargetMarkets} placeholder="Nashville TN, Charlotte NC, Phoenix AZ..."/><div style={{marginTop:12}}><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:8}}>Asset Type Preferences</label><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>{["SFR","Small Multifamily","Mid Multifamily","Large Multifamily","Mixed-Use","Short-Term Rental","Workforce Housing","Student Housing"].map(a=>(<div key={a} onClick={()=>setAssetPrefs(p=>p.includes(a)?p.filter(x=>x!==a):[...p,a])} style={{padding:"6px 10px",border:`1.5px solid ${assetPrefs.includes(a)?"#C5993A":"#e8eaed"}`,borderRadius:6,cursor:"pointer",background:assetPrefs.includes(a)?"#fff8e1":"#fafafa",fontSize:12,color:"#1B2A4A"}}>{assetPrefs.includes(a)?"v ":""}{a}</div>))}</div></div></Card></div><Card><SH title="Category Weights (auto-set by strategy, manually adjustable)"/><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:16}}>{CATS.map(c=>(<div key={c.id}><div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}><span style={{fontSize:12,color:"#555"}}>{c.label}</span><span style={{fontSize:13,fontWeight:700,color:c.color}}>{(weights[c.id]*100).toFixed(0)}%</span></div><input type="range" min={5} max={50} step={5} value={Math.round(weights[c.id]*100)} onChange={e=>setWeights(w=>({...w,[c.id]:+e.target.value/100}))} style={{width:"100%",accentColor:c.color}}/></div>))}</div><p style={{fontSize:11,color:"#aaa",marginTop:12}}>Total weight: {(Object.values(weights).reduce((a,b)=>a+b,0)*100).toFixed(0)}% (should equal 100%)</p></Card></div>}

      {tab==="intake"&&<div><h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:20,fontWeight:700}}>Deal Intake</h2><div style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr",gap:16,marginBottom:16}}><F label="Street Address" value={intake.address} onChange={v=>setI(p=>({...p,address:v}))} placeholder="123 Main Street"/><F label="City" value={intake.city} onChange={v=>setI(p=>({...p,city:v}))} placeholder="Nashville"/><F label="State" value={intake.state} onChange={v=>setI(p=>({...p,state:v}))} placeholder="TN"/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:16,marginBottom:16}}><Sel label="Asset Type" value={intake.assetType} onChange={v=>setI(p=>({...p,assetType:v}))} options={ASSET_TYPES}/><Sel label="Deal Type" value={intake.dealType} onChange={v=>setI(p=>({...p,dealType:v}))} options={DEAL_TYPES}/><F label="Units" value={intake.units} onChange={v=>setI(p=>({...p,units:v}))} placeholder="72" type="number"/><F label="Acquisition Price ($)" value={intake.price} onChange={v=>setI(p=>({...p,price:v}))} placeholder="4500000" type="number"/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:16,marginBottom:16}}><F label="Stabilized NOI ($)" value={intake.noi} onChange={v=>setI(p=>({...p,noi:v}))} placeholder="315000" type="number"/><F label="Gross Rental Income ($)" value={intake.gri} onChange={v=>setI(p=>({...p,gri:v}))} placeholder="420000" type="number"/><F label="Vacancy Rate (%)" value={intake.vacancy} onChange={v=>setI(p=>({...p,vacancy:v}))} placeholder="5" type="number"/><F label="Replacement Cost ($)" value={intake.rc} onChange={v=>setI(p=>({...p,rc:v}))} placeholder="5500000" type="number"/></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:16,marginBottom:16}}><F label="Down Payment (%)" value={intake.down} onChange={v=>setI(p=>({...p,down:v}))} placeholder="25" type="number"/><F label="Loan Rate (%)" value={intake.rate} onChange={v=>setI(p=>({...p,rate:v}))} placeholder="6.5" type="number"/><F label="Amortization (years)" value={intake.yrs} onChange={v=>setI(p=>({...p,yrs:v}))} placeholder="30" type="number"/></div><div><label style={{fontSize:12,color:"#666",fontWeight:600,display:"block",marginBottom:4}}>Deal Notes</label><textarea value={intake.notes} onChange={e=>setI(p=>({...p,notes:e.target.value}))} rows={4} placeholder="Value-add thesis, key assumptions, sponsor background, deal source..." style={{width:"100%",padding:"10px 14px",border:"1.5px solid #ddd",borderRadius:8,fontSize:14,fontFamily:"inherit",resize:"vertical",boxSizing:"border-box"}}/></div>{intake.price&&<div style={{marginTop:24,padding:20,background:"#fff",borderRadius:10,border:"1px solid #e8eaed"}}><p style={{fontSize:12,color:"#888",marginBottom:14,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.06em"}}>Quick Metrics</p><div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:16}}>{[{l:"Cap Rate",v:fmtP(fin.capRate)},{l:"Cash-on-Cash",v:fmtP(fin.coc)},{l:"DSCR",v:fmt(fin.dscr)+"x"},{l:"vs Replacement",v:fin.rcPct>0?fmt(fin.rcPct)+"pct":"--"},{l:"Annual Cash Flow",v:fmtC(fin.cf)}].map(m=>(<div key={m.l} style={{textAlign:"center"}}><div style={{fontSize:22,fontWeight:700,color:"#1B2A4A"}}>{m.v}</div><div style={{fontSize:11,color:"#888",marginTop:2}}>{m.l}</div></div>))}</div></div>}</div>}

      {tab==="scoring"&&<div style={{position:"relative"}}>{isF&&<Locked minTier="starter" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:6,fontWeight:700}}>PAIS Scoring</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Score each category 0-100. Click Discuss on any category to dispute or clarify with the AI.</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>{CATS.map(c=>{const [showChat,setShowChat]=useState(false);return(<div key={c.id} style={{background:"#fff",borderRadius:10,padding:20,border:"1px solid #e8eaed"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><div><div style={{fontWeight:700,color:"#1B2A4A",fontSize:15}}>{c.label}</div><div style={{fontSize:11,color:"#888"}}>Weight: {(weights[c.id]*100).toFixed(0)}pct - Contribution: {(scores[c.id]*weights[c.id]).toFixed(1)} pts</div></div><div style={{display:"flex",alignItems:"center",gap:10}}><button onClick={()=>setShowChat(!showChat)} style={{padding:"4px 10px",background:showChat?"#fff8e1":"#f0f4ff",border:`1px solid ${showChat?"#C5993A":"#c8d8ff"}`,borderRadius:6,fontSize:11,cursor:"pointer",color:showChat?"#7a5c00":"#1B2A4A"}}>{showChat?"Close":"Discuss"}</button><div style={{fontSize:32,fontWeight:800,color:c.color}}>{scores[c.id]}</div></div></div><input type="range" min={0} max={100} value={scores[c.id]} onChange={e=>setSc(p=>({...p,[c.id]:+e.target.value}))} style={{width:"100%",accentColor:c.color,marginBottom:12}}/><div style={{borderTop:"1px solid #f0f0f0",paddingTop:10}}>{GUIDES[c.id].map((g,i)=><p key={i} style={{fontSize:11,color:"#777",margin:"3px 0",lineHeight:1.4}}>{g}</p>)}</div>{showChat&&<div style={{marginTop:16,borderTop:"1px solid #e8eaed",paddingTop:16}}><p style={{fontSize:12,color:"#888",marginBottom:10}}>Discuss the {c.label} score - argue, question, or request clarification.</p><AIPanel deal={deal} mode="dispute"/></div>}</div>);})}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginTop:20}}><Card><p style={{fontSize:13,fontWeight:700,color:"#1B2A4A",marginBottom:12}}>Score Radar</p><ResponsiveContainer width="100%" height={220}><RadarChart data={CATS.map(c=>({subject:c.label.split(" ")[0],score:scores[c.id],fullMark:100}))}><PolarGrid stroke="#eee"/><PolarAngleAxis dataKey="subject" tick={{fontSize:11,fill:"#666"}}/><Radar dataKey="score" stroke="#C5993A" fill="#C5993A" fillOpacity={0.25} strokeWidth={2}/></RadarChart></ResponsiveContainer></Card><Card><p style={{fontSize:13,fontWeight:700,color:"#1B2A4A",marginBottom:12}}>Weighted Contribution</p><ResponsiveContainer width="100%" height={220}><BarChart data={CATS.map(c=>({name:c.label.split(" ")[0],val:scores[c.id]*weights[c.id],color:c.color}))} layout="vertical"><CartesianGrid strokeDasharray="3 3" horizontal={false}/><XAxis type="number" domain={[0,35]} tick={{fontSize:11}}/><YAxis type="category" dataKey="name" tick={{fontSize:11}} width={70}/><Tooltip formatter={v=>v.toFixed(1)+" pts"}/><Bar dataKey="val" radius={[0,4,4,0]}>{CATS.map((c,i)=><Cell key={i} fill={c.color}/>)}</Bar></BarChart></ResponsiveContainer></Card></div><Card style={{marginTop:20}}><p style={{fontSize:13,fontWeight:700,color:"#1B2A4A",marginBottom:12}}>Amendment v1 Flags</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>{[{k:"a1",l:"A1: Subsidized Demand",d:"Section 8/LIHTC - adjust affordability to payment standards"},{k:"a2",l:"A2: Transitional Vacancy",d:"Score on occupancy history not spot vacancy rate"},{k:"a3",l:"A3: Catalytic Investment",d:"Funded public investment in trade area (+up to 15 pts Market)"}].map(a=>(<div key={a.k} onClick={()=>setAm(p=>({...p,[a.k]:!p[a.k]}))} style={{padding:14,border:`2px solid ${amends[a.k]?"#C5993A":"#e8eaed"}`,borderRadius:8,cursor:"pointer",background:amends[a.k]?"#fff8e1":"#fafafa"}}><div style={{fontWeight:700,fontSize:13,color:amends[a.k]?"#C5993A":"#1B2A4A",marginBottom:4}}>{amends[a.k]?"v ":""}{a.l}</div><div style={{fontSize:11,color:"#777",lineHeight:1.4}}>{a.d}</div></div>))}</div></Card></div>}

      {tab==="fin"&&<div><h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:20,fontWeight:700}}>Financial Model</h2>{isF&&<div style={{padding:14,background:"#fff8e1",borderRadius:8,border:"1.5px solid #C5993A",marginBottom:20,fontSize:13,color:"#7a5c00"}}>Free plan shows cap rate and cash-on-cash only. <button onClick={()=>setModal(true)} style={{background:"none",border:"none",color:"#C5993A",fontWeight:700,cursor:"pointer",fontSize:13}}>Upgrade for full model</button></div>}<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}><Card><SH title="Key Metrics"/>{[{l:"Capitalization Rate",v:fmtP(fin.capRate),flag:fin.capRate<5,free:true},{l:"Cash-on-Cash Return",v:fmtP(fin.coc),flag:fin.coc<5,free:true},{l:"DSCR",v:fmt(fin.dscr)+"x",flag:fin.dscr<1.2,free:false},{l:"Gross Rent Multiplier",v:fmt(fin.grm)+"x",free:false},{l:"Annual Cash Flow",v:fmtC(fin.cf),flag:fin.cf<0,free:false},{l:"Monthly Debt Service",v:fmtC(fin.mp),free:false},{l:"Equity Required",v:fmtC(fin.eq),free:false},{l:"Loan Amount",v:fmtC(fin.loan),free:false}].map(m=>(<div key={m.l} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 0",borderBottom:"1px solid #f4f4f4"}}><span style={{fontSize:13,color:"#555"}}>{m.l}</span>{isF&&!m.free?<span style={{fontSize:12,color:"#ccc"}}>Upgrade to view</span>:<span style={{fontSize:16,fontWeight:700,color:m.flag?"#E53935":"#1B2A4A"}}>{m.v}</span>}</div>))}</Card><div><Card style={{marginBottom:16}}><SH title="Replacement Cost Test"/>{fin.rcPct>0?(<div><div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}><span style={{fontSize:13,color:"#555"}}>Acquisition Price</span><span style={{fontWeight:700}}>{fmtC(+intake.price)}</span></div><div style={{display:"flex",justifyContent:"space-between",marginBottom:16}}><span style={{fontSize:13,color:"#555"}}>Replacement Cost</span><span style={{fontWeight:700}}>{fmtC(+intake.rc)}</span></div><div style={{background:"#f4f5f7",borderRadius:8,padding:16,textAlign:"center"}}><div style={{fontSize:36,fontWeight:800,color:fin.rcPct<=70?"#27AE60":fin.rcPct<=85?"#C5993A":"#E53935"}}>{fmt(fin.rcPct)}pct</div><div style={{fontSize:12,color:"#888",marginTop:4}}>of Replacement Cost</div><div style={{fontSize:12,marginTop:8,fontWeight:600,color:fin.rcPct<=70?"#27AE60":fin.rcPct<=85?"#C5993A":"#E53935"}}>{fin.rcPct<=70?"Strong margin of safety":fin.rcPct<=85?"Approaching 85pct threshold":"Hard filter triggered"}</div></div></div>):<p style={{color:"#aaa",fontSize:13}}>Enter price and replacement cost in Deal Intake.</p>}</Card><Card><SH title="Per-Unit Metrics"/>{[{l:"Price per Unit",v:fmtC(fin.ppu)},{l:"NOI per Unit",v:fmtC(fin.noiPpu)},{l:"Cash Flow per Unit",v:fmtC(fin.cf/(+intake.units||1))}].map(m=>(<div key={m.l} style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid #f4f4f4"}}><span style={{fontSize:13,color:"#555"}}>{m.l}</span><span style={{fontSize:16,fontWeight:700,color:"#1B2A4A"}}>{m.v}</span></div>))}</Card></div></div></div>}

      {tab==="sens"&&<div style={{position:"relative"}}>{isF&&<Locked minTier="starter" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:8,fontWeight:700}}>Sensitivity Analysis</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Two-variable heat map: interest rate vs. vacancy. Base case in yellow.</p>{intake.price?<Card style={{marginBottom:24}}><SensTable f={intake}/></Card>:<div style={{padding:40,textAlign:"center",color:"#aaa",background:"#fff",borderRadius:10}}>Enter acquisition price in Deal Intake first.</div>}<Card><SH title="Scenario Comparison"/><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:16}}>{[{l:"Bear Case",v:+intake.vacancy+10,r:+intake.rate+1,c:"#E53935"},{l:"Base Case",v:+intake.vacancy,r:+intake.rate,c:"#C5993A"},{l:"Bull Case",v:Math.max(0,+intake.vacancy-3),r:+intake.rate-0.5,c:"#27AE60"}].map(s=>{const sf=calcFin({...intake,vacancy:s.v,rate:s.r});return(<div key={s.l} style={{padding:20,border:`2px solid ${s.c}`,borderRadius:10,background:"#fafafa"}}><div style={{fontSize:15,fontWeight:700,color:s.c,marginBottom:8}}>{s.l}</div><div style={{fontSize:11,color:"#888",marginBottom:12}}>Vacancy: {s.v.toFixed(0)}pct | Rate: {s.r.toFixed(1)}pct</div>{[{l:"CoC Return",v:fmtP(sf.coc)},{l:"Cash Flow",v:fmtC(sf.cf)},{l:"DSCR",v:fmt(sf.dscr)+"x"}].map(m=>(<div key={m.l} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:"1px solid #eee"}}><span style={{fontSize:12,color:"#666"}}>{m.l}</span><span style={{fontSize:14,fontWeight:700,color:s.c}}>{m.v}</span></div>))}</div>);})}</div></Card></div>}

      {tab==="filters"&&<div style={{position:"relative"}}>{isF&&<Locked minTier="starter" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:8,fontWeight:700}}>Hard Filters</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Set your thresholds. Filters auto-trigger when deal data crosses your threshold. Override manually for any filter.</p><div style={{display:"flex",flexDirection:"column",gap:14}}>{HF_DEFAULTS.map(f=>{const autoT=(()=>{if(f.metric&&fin[f.metric]!==undefined){const val=fin[f.metric];if(f.dir==="above")return val>hfT[f.id];if(f.dir==="below")return val<hfT[f.id];}return false;})();const status=hfO[f.id]==="auto"?(autoT?"flagged":"clear"):hfO[f.id];const isFlagged=status==="flagged";return(<Card key={f.id} style={{border:`1.5px solid ${isFlagged?"#E53935":"#e8eaed"}`}}><div style={{display:"flex",alignItems:"flex-start",gap:16}}><div style={{fontSize:20,marginTop:2}}>{isFlagged?"[!]":"[ok]"}</div><div style={{flex:1}}><div style={{fontWeight:600,color:"#1B2A4A",fontSize:14,marginBottom:8}}>{f.label}</div>{f.fmt!=="flag"&&<div style={{marginBottom:12}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}><span style={{fontSize:12,color:"#888"}}>Threshold: {hfT[f.id].toFixed(f.fmt==="x"?2:0)}{f.fmt==="pct"?"pct":f.fmt==="x"?"x":""}</span>{f.metric&&fin[f.metric]!==undefined&&<span style={{fontSize:12,color:isFlagged?"#E53935":"#27AE60",fontWeight:600}}>Actual: {fin[f.metric].toFixed(f.fmt==="x"?2:1)}{f.fmt==="pct"?"pct":f.fmt==="x"?"x":""}</span>}</div><input type="range" min={f.min} max={f.max} step={f.fmt==="x"?0.05:1} value={hfT[f.id]} onChange={e=>setHfT(p=>({...p,[f.id]:+e.target.value}))} style={{width:"100%",accentColor:isFlagged?"#E53935":"#27AE60"}}/><div style={{display:"flex",justifyContent:"space-between",fontSize:10,color:"#aaa"}}><span>{f.min}{f.fmt==="pct"?"pct":f.fmt==="x"?"x":""}</span><span>{f.max}{f.fmt==="pct"?"pct":f.fmt==="x"?"x":""}</span></div></div>}<div style={{display:"flex",gap:8,alignItems:"center"}}><span style={{fontSize:11,color:"#888"}}>Override:</span>{["auto","clear","monitor","flagged"].map(s=>(<button key={s} onClick={()=>setHfO(p=>({...p,[f.id]:s}))} style={{padding:"4px 10px",border:"1.5px solid",borderColor:hfO[f.id]===s?(s==="flagged"?"#E53935":s==="monitor"?"#E67E22":s==="clear"?"#27AE60":"#4A90D9"):"#ddd",borderRadius:4,fontSize:11,cursor:"pointer",fontWeight:hfO[f.id]===s?700:400,background:hfO[f.id]===s?(s==="flagged"?"#ffebee":s==="monitor"?"#fff3e0":s==="clear"?"#e8f5e9":"#e8f0ff"):"#fff",color:hfO[f.id]===s?(s==="flagged"?"#E53935":s==="monitor"?"#E67E22":s==="clear"?"#27AE60":"#4A90D9"):"#888",textTransform:"capitalize"}}>{s}</button>))}</div></div></div></Card>);})} </div>{flagged.length>0&&<div style={{marginTop:20,padding:16,background:"#ffebee",borderRadius:8,border:"1.5px solid #E53935"}}><p style={{fontWeight:700,color:"#E53935",marginBottom:6}}>Flag: {flagged.length} filter{flagged.length>1?"s":""} flagged - must be addressed before IC submission</p>{flagged.map(f=><p key={f.id} style={{fontSize:13,color:"#c62828",margin:"2px 0"}}>- {f.label}</p>)}</div>}</div>}

      {tab==="ai"&&<div style={{position:"relative"}}>{trial.rank<2&&<Locked minTier="pro" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:8,fontWeight:700}}>AI Research</h2><p style={{color:"#666",fontSize:14,marginBottom:24}}>Ask anything about this deal. Full conversation history maintained. Deal context passed automatically.</p><Card><AIPanel deal={deal} mode="research"/></Card></div>}

      {tab==="offdocs"&&<OfferingDocs deal={deal} trial={trial} onUpgrade={()=>setModal(true)}/>}

      {tab==="results"&&<div style={{position:"relative"}}>{isF&&<Locked minTier="starter" onUpgrade={()=>setModal(true)}/>}<h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:20,fontWeight:700}}>Results and Deal Memo</h2><div style={{marginBottom:20,padding:16,background:"#fff",borderRadius:10,border:"1px solid #e8eaed",display:"flex",alignItems:"center",justifyContent:"space-between"}}><div><span style={{fontSize:14,fontWeight:700,color:"#1B2A4A"}}>Export Options</span><span style={{fontSize:12,color:"#888",marginLeft:12}}>{trial.rank>=2?"Download your IC memo as a formatted document.":"PDF export available on Pro ($19.99/mo) and above."}</span></div>{trial.rank>=2?<button onClick={()=>{const txt="PAIS INVESTMENT COMMITTEE MEMORANDUM\n"+"=".repeat(50)+"\n\nProperty: "+(intake.address||"TBD")+", "+(intake.city||"")+" "+(intake.state||"")+"\nAsset: "+intake.assetType+" | Deal: "+intake.dealType+(intake.units?" | "+intake.units+" units":"")+"\nDate: "+new Date().toLocaleDateString()+"\n\n"+"-".repeat(50)+"\nKEY METRICS\n"+"-".repeat(50)+"\nAcquisition Price: "+fmtC(+intake.price)+"\nCap Rate: "+fmtP(fin.capRate)+"\nCash-on-Cash: "+fmtP(fin.coc)+"\nDSCR: "+fmt(fin.dscr)+"x\nAnnual Cash Flow: "+fmtC(fin.cf)+"\nvs Replacement Cost: "+(fin.rcPct>0?fmt(fin.rcPct)+"pct":"N/A")+"\n\n"+"-".repeat(50)+"\nPAIS COMPOSITE SCORE: "+comp.toFixed(0)+" - "+b.label+"\n"+"-".repeat(50)+"\n"+CATS.map(c=>(c.label+": "+scores[c.id]+"/100 ("+(weights[c.id]*100).toFixed(0)+"pct wt = "+(scores[c.id]*weights[c.id]).toFixed(1)+" pts)")).join("\n")+"\n\n"+(intake.notes?"NOTES: "+intake.notes+"\n\n":"")+"-".repeat(50)+"\nDecision: "+b.label+"\n"+(flagged.length>0?"Flags: "+flagged.map(f=>f.label).join("; "):"No hard filters triggered")+"\n\n"+"-".repeat(50)+"\nGenerated by PAIS Deal Evaluation Platform\n";const blob=new Blob([txt],{type:"text/plain"});const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download="PAIS_Memo_"+(intake.address||"Deal").replace(/\s+/g,"_")+".txt";a.click();URL.revokeObjectURL(url);}} style={{padding:"8px 18px",background:"#1B2A4A",color:"#C5993A",border:"none",borderRadius:6,fontSize:13,fontWeight:700,cursor:"pointer"}}>Download Memo</button>:<button onClick={()=>setModal(true)} style={{padding:"8px 18px",background:"#f0f0f0",color:"#999",border:"1.5px solid #ddd",borderRadius:6,fontSize:13,fontWeight:700,cursor:"pointer"}}>[locked] Upgrade to export</button>}</div><Card style={{border:`2px solid ${b.border}`,marginBottom:24}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}><div><div style={{fontSize:13,color:"#888",textTransform:"uppercase",letterSpacing:"0.1em",marginBottom:4}}>PAIS Composite Score</div><div style={{fontSize:72,fontWeight:900,color:b.color,lineHeight:1}}>{comp.toFixed(0)}</div><div style={{fontSize:22,fontWeight:700,color:b.color,marginTop:4}}>{b.label}</div>{intake.address&&<div style={{fontSize:14,color:"#666",marginTop:8}}>{intake.address}{intake.city?`, ${intake.city}`:""}{intake.state?`, ${intake.state}`:""}</div>}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>{CATS.map(c=>(<div key={c.id} style={{textAlign:"center",padding:"10px 14px",background:"#fafafa",borderRadius:8,border:"1px solid #eee"}}><div style={{fontSize:22,fontWeight:800,color:c.color}}>{scores[c.id]}</div><div style={{fontSize:10,color:"#777",marginTop:2,lineHeight:1.3}}>{c.label}</div><div style={{fontSize:10,color:"#aaa"}}>{(weights[c.id]*100).toFixed(0)}pct wt</div></div>))}</div></div></Card><Card><div style={{borderBottom:"2px solid #C5993A",paddingBottom:16,marginBottom:20}}><div style={{fontSize:11,color:"#888",letterSpacing:"0.1em",textTransform:"uppercase"}}>Investment Committee Memorandum</div><div style={{fontSize:20,fontWeight:700,color:"#1B2A4A",marginTop:4}}>{intake.address||"Subject Property"}{intake.city?" - "+intake.city:""}{intake.state?", "+intake.state:""}</div><div style={{fontSize:13,color:"#666",marginTop:4}}>{intake.assetType} | {intake.dealType}{intake.units?" | "+intake.units+" units":""} | Prepared {new Date().toLocaleDateString()}</div></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:16,marginBottom:24,padding:16,background:"#f8f9fa",borderRadius:8}}>{[{l:"Acquisition Price",v:fmtC(+intake.price)},{l:"Cap Rate",v:fmtP(fin.capRate)},{l:"DSCR",v:fmt(fin.dscr)+"x"},{l:"PAIS Score",v:comp.toFixed(0)+" - "+b.label}].map(m=>(<div key={m.l}><div style={{fontSize:11,color:"#888",marginBottom:2}}>{m.l}</div><div style={{fontSize:15,fontWeight:700,color:"#1B2A4A"}}>{m.v}</div></div>))}</div><div style={{fontSize:14,lineHeight:1.8,color:"#333"}}><p><strong>Decision:</strong> <span style={{color:b.color,fontWeight:700}}>{b.label}</span> - Composite PAIS score of {comp.toFixed(0)}/100.</p>{flagged.length>0&&<p><strong>Hard Filter Flags ({flagged.length}):</strong> {flagged.map(f=>f.label).join("; ")}. These must be addressed before commitment.</p>}<p><strong>Financial Summary:</strong> Acquisition price of {fmtC(+intake.price)} implies a cap rate of {fmtP(fin.capRate)}, cash-on-cash return of {fmtP(fin.coc)}, and DSCR of {fmt(fin.dscr)}x. Annual cash flow of {fmtC(fin.cf)}.{fin.rcPct>0?" Acquisition represents "+fmt(fin.rcPct)+"pct of estimated replacement cost.":""}</p><p><strong>Category Scores:</strong> {CATS.map(c=>c.label.split(" ")[0]+": "+scores[c.id]).join(" | ")}.</p>{amends.a1&&<p><strong>Amendment A1:</strong> Subsidized Demand active. Affordability adjusted to Section 8 payment standards.</p>}{amends.a2&&<p><strong>Amendment A2:</strong> Transitional Vacancy active. Vacancy scored on occupancy history not spot rate.</p>}{amends.a3&&<p><strong>Amendment A3:</strong> Catalytic Investment active. Funded public investment within trade area identified.</p>}{intake.notes&&<p><strong>Notes:</strong> {intake.notes}</p>}</div></Card></div>}

      {tab==="pipeline"&&<div><h2 style={{fontSize:20,color:"#1B2A4A",marginBottom:8,fontWeight:700}}>Deal Pipeline</h2>{isF&&<p style={{fontSize:13,color:"#888",marginBottom:16}}>Free plan: up to 3 saved deals. Upgrade for unlimited.</p>}{pipe.length===0?<div style={{padding:60,textAlign:"center",background:"#fff",borderRadius:10,color:"#aaa"}}><div style={{fontSize:40,marginBottom:12}}>[ ]</div><p>No deals saved yet. Score a deal and click Save.</p></div>:<div style={{display:"flex",flexDirection:"column",gap:12}}>{pipe.map(d=>{const db=getBand(d.comp);return(<div key={d.id} style={{background:"#fff",borderRadius:10,padding:20,border:`1.5px solid ${db.border}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}><div><div style={{fontWeight:700,color:"#1B2A4A",fontSize:16}}>{d.address}</div><div style={{fontSize:13,color:"#666",marginTop:2}}>{d.city}{d.state?", "+d.state:""} | {d.assetType} | Saved {d.saved}</div></div><div style={{display:"flex",alignItems:"center",gap:20}}>{d.price&&<div style={{textAlign:"right"}}><div style={{fontSize:12,color:"#888"}}>Price</div><div style={{fontWeight:700,color:"#1B2A4A"}}>${(+d.price).toLocaleString()}</div></div>}{d.capRate>0&&<div style={{textAlign:"right"}}><div style={{fontSize:12,color:"#888"}}>Cap Rate</div><div style={{fontWeight:700,color:"#1B2A4A"}}>{d.capRate.toFixed(2)}pct</div></div>}<div style={{textAlign:"center",padding:"10px 20px",background:db.bg,border:`2px solid ${db.border}`,borderRadius:8}}><div style={{fontSize:24,fontWeight:800,color:db.color}}>{d.comp.toFixed(0)}</div><div style={{fontSize:10,color:db.color,fontWeight:700,textTransform:"uppercase"}}>{d.band}</div></div></div></div>);})}</div>}</div>}

    </div>
    {modal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.55)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}} onClick={()=>setModal(false)}><div onClick={e=>e.stopPropagation()} style={{maxWidth:620,width:"90%",background:"#fff",borderRadius:16,border:"2px solid #C5993A",padding:"40px 36px",boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:24}}><div><h2 style={{fontSize:22,fontWeight:800,color:"#1B2A4A",margin:0}}>Choose Your Plan</h2><p style={{fontSize:13,color:"#888",marginTop:4}}>Annual plans save 20pct | Cancel anytime | All deals preserved</p></div><button onClick={()=>setModal(false)} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:"#aaa"}}>x</button></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:20}}>{PLANS.map(p=><PlanCard key={p.tier} p={p} onClick={()=>simUpgrade(p.tier)}/>)}</div><p style={{fontSize:11,color:"#bbb",textAlign:"center"}}>Billed via Stripe | Cancel anytime | All deals preserved on any plan</p><p style={{fontSize:10,color:"#ddd",textAlign:"center",marginTop:4}}>[Demo: click a plan to simulate upgrade]</p></div></div>}
  </div>);
}
